USE ProjectTrackerDB;
GO

-- Step 1: Update existing warehouses to match branch codes
PRINT 'Updating existing warehouses...';

UPDATE Warehouses SET Code = 'WH-CPT', Name = 'CPT Warehouse' WHERE Id = 3;
UPDATE Warehouses SET Code = 'WH-PE', Name = 'PE Warehouse' WHERE Id = 4;

-- Step 2: Add PVT and BOND warehouses
PRINT 'Adding PVT and BOND warehouses...';

SET IDENTITY_INSERT Warehouses ON;

IF NOT EXISTS (SELECT 1 FROM Warehouses WHERE Id = 5)
VALUES (5, 'PVT Warehouse', 'WH-PVT', 'Private', 'National', 50000, 50000, 'Active', GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM Warehouses WHERE Id = 6)
VALUES (6, 'BOND Warehouse', 'WH-BOND', 'Bond Store', 'National', 50000, 50000, 'Active', GETUTCDATE());

SET IDENTITY_INSERT Warehouses OFF;

