-- Step 4: Import ALL items as BuildingInventory
PRINT 'Importing 794 items into BuildingInventory...';

-- Clear any existing building inventory
DELETE FROM BuildingInventory;















































































































































































































































































































-- Step 5: Verify results
PRINT 'Seed complete. Verifying...';

SELECT 'Warehouses' AS [Table], COUNT(*) AS [Count] FROM Warehouses;
SELECT 'Buildings' AS [Table], COUNT(*) AS [Count] FROM WarehouseBuildings;
SELECT 'Inventory Items' AS [Table], COUNT(*) AS [Count] FROM BuildingInventory;
SELECT 'Items with Stock' AS [Metric], COUNT(*) AS [Count] FROM BuildingInventory WHERE QuantityOnHand > 0;

SELECT w.Name AS Warehouse, wb.Name AS Division, COUNT(bi.Id) AS Items,
  SUM(CASE WHEN bi.QuantityOnHand > 0 THEN 1 ELSE 0 END) AS WithStock,
  CAST(SUM(bi.QuantityOnHand) AS INT) AS TotalQty
FROM Warehouses w
JOIN WarehouseBuildings wb ON wb.WarehouseId = w.Id
LEFT JOIN BuildingInventory bi ON bi.BuildingId = wb.Id
GROUP BY w.Name, wb.Name
ORDER BY w.Name, wb.Name;

PRINT 'Successfully imported 15086 inventory records (307 with stock) from 794 items.';
GO